components.css:
h1 {
  font-size: var(--a-text-3xl);
  font-weight: var(--a-font-weight-bold);
  line-height: var(--a-line-height-tight);
  margin-bottom: var(--a-space-md);
  color: var(--a-text-main);
}

h2 {
  font-size: var(--a-text-2xl);
  font-weight: var(--a-font-weight-semibold);
  line-height: var(--a-line-height-tight);
  margin-top: var(--a-space-2xl);
  margin-bottom: var(--a-space-md);
  color: var(--a-text-main);
}

h3 {
  font-size: var(--a-text-lg);
  font-weight: var(--a-font-weight-semibold);
  line-height: var(--a-line-height-tight);
  margin-top: var(--a-space-lg);
  margin-bottom: var(--a-space-sm);
  color: var(--a-text-main);
}

p {
  font-size: var(--a-text-base);
  line-height: var(--a-line-height-normal);
  margin-bottom: var(--a-space-md);
  color: var(--a-text-main);
  max-width: var(--a-width-prose);
}

em {
  font-style: italic;
  color: var(--a-text-main);
}

strong {
  font-weight: var(--a-font-weight-semibold);
  color: var(--a-primary);
}

small {
  font-size: var(--a-text-sm);
  color: var(--a-text-secondary);
  line-height: var(--a-line-height-normal);
}

code {
  background: var(--a-surface-overlay);
  color: var(--a-text-main);
  padding: 0.2em 0.4em;
  border-radius: var(--a-radius-sm);
  font-family: var(--a-font-family-mono);
  font-size: 0.9em;
}

blockquote {
  margin: var(--a-space-md) 0;
  padding-left: var(--a-space-md);
  border-left: 4px solid var(--a-primary);
  color: var(--a-text-secondary);
  font-style: italic;
}

blockquote footer {
  font-style: normal;
  color: var(--a-text-muted);
  font-size: var(--a-text-sm);
}
